@WebMvcTest(UserController.class)
class UserControllerTest {

    @Autowired
    private MockMvc mockMvc;

    @Autowired
    private ObjectMapper objectMapper;

    @MockBean
    private UserService userService;

    @Test
    void createUser_WithValidData_ReturnsCreated() throws Exception {
        // Arrange
        CreateUserRequest request = new CreateUserRequest(
                "John Doe", "john@example.com", "password123"
        );
        UserResponse response = new UserResponse(1L, "John Doe", "john@example.com");

        when(userService.create(any(CreateUserRequest.class))).thenReturn(response);

        // Act & Assert
        mockMvc.perform(post("/api/v1/users")
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(objectMapper.writeValueAsString(request)))
                .andExpect(status().isCreated())
                .andExpect(jsonPath("$.id").value(1))
                .andExpect(jsonPath("$.name").value("John Doe"));
    }

    @Test
    void getUser_WhenNotFound_Returns404() throws Exception {
        // Arrange
        when(userService.findById(999L)).thenThrow(new NotFoundException("User not found"));

        // Act & Assert
        mockMvc.perform(get("/api/v1/users/999"))
                .andExpect(status().isNotFound());
    }
}

@ExtendWith(MockitoExtension.class)
class UserServiceTest {

    @Mock
    private UserRepository userRepository;

    @Mock
    private UserMapper userMapper;

    @Mock
    private PasswordEncoder passwordEncoder;

    @InjectMocks
    private UserService userService;

    @Test
    void create_EncodesPassword() {
        // Arrange
        CreateUserRequest request = new CreateUserRequest(
                "John", "john@example.com", "plaintext"
        );
        User user = User.builder()
                .id(1L)
                .name("John")
                .email("john@example.com")
                .password("encoded")
                .build();
        UserResponse response = new UserResponse(1L, "John", "john@example.com");

        when(passwordEncoder.encode("plaintext")).thenReturn("encoded");
        when(userMapper.toEntity(request)).thenReturn(user);
        when(userRepository.save(any(User.class))).thenReturn(user);
        when(userMapper.toResponse(user)).thenReturn(response);

        // Act
        userService.create(request);

        // Assert
        verify(passwordEncoder).encode("plaintext");
        verify(userRepository).save(argThat(u -> u.getPassword().equals("encoded")));
    }

    @Test
    void findById_WhenNotExists_ThrowsException() {
        // Arrange
        when(userRepository.findById(999L)).thenReturn(Optional.empty());

        // Act & Assert
        assertThatThrownBy(() -> userService.findById(999L))
                .isInstanceOf(NotFoundException.class)
                .hasMessageContaining("User");
    }
}

class UserServiceTest {

    private UserRepository userRepository;
    private UserService userService;

    @BeforeEach
    void setUp() {
        userRepository = mock(UserRepository.class);
        userService = new UserService(userRepository);  // Manual setup
    }

    @Test
    void findById_WhenNotExists_ThrowsException() {
        when(userRepository.findById(999L)).thenReturn(Optional.empty());
        assertThatThrownBy(() -> userService.findById(999L))
                .isInstanceOf(NotFoundException.class);
    }
}

@DataJpaTest
class UserRepositoryTest {

    @Autowired
    private UserRepository userRepository;

    @Autowired
    private TestEntityManager entityManager;

    @Test
    void findByIdWithRoles_LoadsRoles() {
        // Arrange
        User user = User.builder()
                .name("John")
                .email("john@example.com")
                .build();
        Role role = new Role("ADMIN");
        user.getRoles().add(role);
        entityManager.persistAndFlush(user);

        // Act
        Optional<User> found = userRepository.findByIdWithRoles(user.getId());

        // Assert
        assertThat(found).isPresent();
        assertThat(found.get().getRoles())
                .hasSize(1)
                .extracting(Role::getName)
                .contains("ADMIN");
    }

    @Test
    void search_WithFilter_ReturnsMatching() {
        // Arrange
        entityManager.persistAndFlush(User.builder().name("Alice").isActive(true).build());
        entityManager.persistAndFlush(User.builder().name("Bob").isActive(false).build());

        // Act
        Page<User> results = userRepository.search("Alice", true, PageRequest.of(0, 10));

        // Assert
        assertThat(results.getContent())
                .hasSize(1)
                .extracting(User::getName)
                .contains("Alice");
    }
}

@SpringBootTest(webEnvironment = RANDOM_PORT)
@Testcontainers
class UserApiIntegrationTest {

    @Autowired
    private TestRestTemplate restTemplate;

    @Autowired
    private UserRepository userRepository;

    @Container
    static PostgreSQLContainer<?> postgres = new PostgreSQLContainer<>("postgres:15")
            .withDatabaseName("testdb")
            .withUsername("test")
            .withPassword("test");

    @DynamicPropertySource
    static void configureTestContainer(DynamicPropertyRegistry registry) {
        registry.add("spring.datasource.url", postgres::getJdbcUrl);
        registry.add("spring.datasource.username", postgres::getUsername);
        registry.add("spring.datasource.password", postgres::getPassword);
    }

    @Test
    void createUser_PersistsToDatabase() {
        // Arrange
        CreateUserRequest request = new CreateUserRequest(
                "John Doe", "john@example.com", "password123"
        );

        // Act
        ResponseEntity<UserResponse> response = restTemplate.postForEntity(
                "/api/v1/users", request, UserResponse.class
        );

        // Assert
        assertThat(response.getStatusCode()).isEqualTo(HttpStatus.CREATED);
        User saved = userRepository.findByEmail("john@example.com").orElseThrow();
        assertThat(saved.getName()).isEqualTo("John Doe");
    }
}

@ExtendWith(MockitoExtension.class)
class UserValidationTest {

    @InjectMocks
    private UserService userService;

    @ParameterizedTest
    @ValueSource(strings = {"", "invalid", "missing@", "@example.com"})
    void validate_InvalidEmail_Throws(String email) {
        // Act & Assert
        assertThatThrownBy(() -> userService.validate(new CreateUserRequest("John", email, "password")))
                .isInstanceOf(ValidationException.class);
    }

    @ParameterizedTest
    @CsvSource({
            "John, john@example.com, true",
            "Alice, alice@example.com, true",
            "'', invalid, false",
            "Bob, '', false"
    })
    void validate_MultipleFields(String name, String email, boolean shouldSucceed) {
        CreateUserRequest request = new CreateUserRequest(name, email, "password");

        if (shouldSucceed) {
            assertThatNoException().isThrownBy(() -> userService.validate(request));
        } else {
            assertThatThrownBy(() -> userService.validate(request))
                    .isInstanceOf(ValidationException.class);
        }
    }
}
